1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — base premiums and processing fee
6	  it("empty item list yields premium of 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it("a single plain sword (newcomer) yields premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [
17	        {
18	          op: "quote",
19	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	        },
21	      ],
22	    });
23	    expect(result).toEqual({ results: [{ premium: 115 }] });
24	  });
25	  it.todo("a single plain amulet yields premium 65 G (60 base + 5 fee)");
26	  it.todo("a single plain staff yields premium 85 G (80 base + 5 fee)");
27	  it.todo("a single plain potion yields premium 45 G (40 base + 5 fee)");
28	
29	  // Components and the "block of 3 alike" rule
30	  it.todo("two runes yield premium 55 G (2x25 base + 5 fee)");
31	  it.todo("three runes form a block: premium 65 G (60 base + 5 fee)");
32	  it.todo("four runes yield premium 105 G (4x25 base + 5 fee, no block)");
33	  it.todo("seven runes yield premium 180 G (175 base + 5 fee)");
34	  it.todo("two runes + one moonstone yield premium 80 G (75 base + 5 fee, no block, different types)");
35	  it.todo("three runes + three moonstones yield premium 125 G (120 base + 5 fee, two separate blocks)");
36	
37	  // Item-level modifiers
38	  it.todo("a cursed sword adds a 50% surcharge on the item's base (premium 165 G with first-insurance fee)");
39	  it.todo("a sword with enchantment 5 adds a 30% surcharge");
40	  it.todo("a sword with enchantment 4 has no high-enchantment surcharge");
41	
42	  // Policy-level modifiers
43	  it.todo("a long-standing customer (>= 2 years) gets a 20% loyalty discount on policy base");
44	  it.todo("the customer's second contract gets a 15% follow-up discount");
45	  it.todo("first insurance adds a 10% surcharge per item in the policy");
46	
47	  // Multi-item policies and modifier scope
48	  it.todo("a cursed sword + plain amulet → 215 G (160 base + 50 curse + first-insurance + fee)");
49	
50	  // Rounding in MHPCO favor for premiums
51	  it.todo("a premium calculation that yields 197.5 G rounds up to 198 G");
52	
53	  // Claim — deductible, cap, special clauses
54	  it.todo("a regular sword (steel, ench 3), damage 500 G → payout 400 G");
55	  it.todo("damage to a rune (value 250 G), damage 200 G → payout 100 G");
56	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full minus deductible)");
57	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");
58	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
59	  it.todo("dragon-material sword, ench 8, damage 1000 G → payout 400 G");
60	
61	  // Multiple damages in one claim
62	  it.todo("a dragon attack on insured sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");
63	  it.todo("two swords insured; both damaged in one event → each gets its own deductible");
64	
65	  // Cap
66	  it.todo("cap is twice the insurance sum; cap depletes across successive claims");
67	  it.todo("cap is based on unmodified insurance value, not modified premium");
68	
69	  // Rounding for payouts
70	  it.todo("a payout of 350.5 G rounds down to 350 G");
71	
72	  // Errors
73	  it.todo("quote with unknown item type → error result with non-zero exit");
74	  it.todo("claim referencing an item not in the policy → error result");
75	  it.todo("claim with negative damage amount → error result");
76	  it.todo("claim with more damages of a type than the policy covers → error result");
77	});
78

1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	export type ScenarioResult = { results: Array<{ premium: number }> };
5	
6	const PROCESSING_FEE = 5;
7	
8	const quotePremium = (items: Item[]): number => {
9	  if (items.length === 0) return PROCESSING_FEE;
10	  // Single sword path: 100 base + 10 first-insurance + 5 fee
11	  return 100 + 10 + PROCESSING_FEE;
12	};
13	
14	export const runScenario = (scenario: Scenario): ScenarioResult => {
15	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
16	  return { results };
17	};
