const PROCESSING_FEE = 5;
const SWORD_BASE = 100;
const FIRST_INSURANCE_SURCHARGE = 10;

const quotePremium = (items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  return SWORD_BASE + FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
};
